FILES = {'src/claire/internet_operations_dashboard/__init__.py': '\nfrom .service import InternetOperationsDashboardService\nfrom .models import DashboardSnapshot, DashboardPanelStatus\nfrom .payloads import DashboardPayloadBuilder\n\n__all__ = [\n    "InternetOperationsDashboardService",\n    "DashboardSnapshot",\n    "DashboardPanelStatus",\n    "DashboardPayloadBuilder",\n]\n', 'src/claire/internet_operations_dashboard/models.py': '\nfrom __future__ import annotations\n\nfrom dataclasses import dataclass, field, asdict\nfrom datetime import datetime, timezone\nfrom typing import Any, Dict, List\n\n\ndef utc_now() -> str:\n    return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")\n\n\n@dataclass\nclass DashboardPanelStatus:\n    panel: str\n    status: str\n    count: int = 0\n    warnings: List[str] = field(default_factory=list)\n    errors: List[str] = field(default_factory=list)\n\n    def to_dict(self) -> Dict[str, Any]:\n        return asdict(self)\n\n\n@dataclass\nclass DashboardSnapshot:\n    status: str\n    generated_at: str = field(default_factory=utc_now)\n    panels: List[Dict[str, Any]] = field(default_factory=list)\n    campaigns: List[Dict[str, Any]] = field(default_factory=list)\n    schedules: List[Dict[str, Any]] = field(default_factory=list)\n    scheduler_reports: List[Dict[str, Any]] = field(default_factory=list)\n    stability: Dict[str, Any] = field(default_factory=dict)\n    source_trust_profiles: List[Dict[str, Any]] = field(default_factory=list)\n    source_trust_events: List[Dict[str, Any]] = field(default_factory=list)\n    recommendations: List[str] = field(default_factory=list)\n\n    def to_dict(self) -> Dict[str, Any]:\n        return asdict(self)\n', 'src/claire/internet_operations_dashboard/payloads.py': '\nfrom __future__ import annotations\n\nfrom typing import Any, Dict, List\n\nfrom .models import DashboardPanelStatus, DashboardSnapshot\n\n\nclass DashboardPayloadBuilder:\n    def build(\n        self,\n        campaigns: List[Dict[str, Any]],\n        schedules: List[Dict[str, Any]],\n        scheduler_reports: List[Dict[str, Any]],\n        stability: Dict[str, Any],\n        source_trust_profiles: List[Dict[str, Any]],\n        source_trust_events: List[Dict[str, Any]],\n    ) -> Dict[str, Any]:\n        panels = [\n            self._panel("campaigns", campaigns),\n            self._panel("schedules", schedules),\n            self._panel("scheduler_reports", scheduler_reports),\n            self._health_panel(stability),\n            self._panel("source_trust_profiles", source_trust_profiles),\n            self._panel("source_trust_events", source_trust_events),\n        ]\n\n        overall = "healthy"\n        if any(panel["status"] == "error" for panel in panels):\n            overall = "error"\n        elif any(panel["status"] in {"degraded", "warning"} for panel in panels):\n            overall = "degraded"\n\n        snapshot = DashboardSnapshot(\n            status=overall,\n            panels=panels,\n            campaigns=campaigns,\n            schedules=schedules,\n            scheduler_reports=scheduler_reports,\n            stability=stability,\n            source_trust_profiles=source_trust_profiles,\n            source_trust_events=source_trust_events,\n            recommendations=self._recommendations(campaigns, schedules, stability, source_trust_profiles),\n        )\n        return snapshot.to_dict()\n\n    def _panel(self, name: str, items: List[Dict[str, Any]]) -> Dict[str, Any]:\n        return DashboardPanelStatus(panel=name, status="healthy", count=len(items)).to_dict()\n\n    def _health_panel(self, stability: Dict[str, Any]) -> Dict[str, Any]:\n        status = str(stability.get("status", "unknown"))\n        panel_status = "healthy" if status == "healthy" else ("degraded" if status in {"degraded", "not_ready"} else "warning")\n        return DashboardPanelStatus(\n            panel="internet_runtime_health",\n            status=panel_status,\n            count=1 if stability else 0,\n            warnings=stability.get("missing_data_paths", []) if isinstance(stability, dict) else [],\n            errors=stability.get("missing_required_paths", []) if isinstance(stability, dict) else [],\n        ).to_dict()\n\n    def _recommendations(\n        self,\n        campaigns: List[Dict[str, Any]],\n        schedules: List[Dict[str, Any]],\n        stability: Dict[str, Any],\n        source_trust_profiles: List[Dict[str, Any]],\n    ) -> List[str]:\n        recs = []\n        if campaigns and not schedules:\n            recs.append("Create schedules for active internet campaigns.")\n        if stability.get("status") == "not_ready":\n            recs.append("Resolve missing required internet runtime modules before launch.")\n        if any(item.get("status") == "quarantined" for item in source_trust_profiles):\n            recs.append("Review quarantined sources before relying on their evidence.")\n        if not campaigns:\n            recs.append("Create at least one persistent campaign before launch validation.")\n        return recs\n', 'src/claire/internet_operations_dashboard/service.py': '\nfrom __future__ import annotations\n\nfrom typing import Any, Dict\n\nfrom claire.dynamic_source_trust.service import DynamicSourceTrustService\nfrom claire.governed_campaign_scheduler.service import GovernedCampaignSchedulerService\nfrom claire.internet_runtime_stability.service import InternetRuntimeStabilityService\nfrom claire.persistent_internet_campaigns.service import PersistentInternetCampaignService\n\nfrom .payloads import DashboardPayloadBuilder\n\n\nclass InternetOperationsDashboardService:\n    def __init__(\n        self,\n        campaign_service: PersistentInternetCampaignService | None = None,\n        scheduler_service: GovernedCampaignSchedulerService | None = None,\n        stability_service: InternetRuntimeStabilityService | None = None,\n        source_trust_service: DynamicSourceTrustService | None = None,\n    ) -> None:\n        self.campaign_service = campaign_service or PersistentInternetCampaignService()\n        self.scheduler_service = scheduler_service or GovernedCampaignSchedulerService()\n        self.stability_service = stability_service or InternetRuntimeStabilityService()\n        self.source_trust_service = source_trust_service or DynamicSourceTrustService()\n        self.builder = DashboardPayloadBuilder()\n\n    def snapshot(self) -> Dict[str, Any]:\n        campaigns = self._safe(self.campaign_service.list_campaigns, [])\n        schedules = self._safe(self.scheduler_service.list_schedules, [])\n        scheduler_reports = self._safe(self.scheduler_service.list_reports, [])\n        stability = self._safe(self.stability_service.health, {"status": "unknown"})\n        profiles = self._safe(self.source_trust_service.list_profiles, [])\n        events = self._safe(lambda: self.source_trust_service.list_events(limit=25), [])\n\n        return self.builder.build(\n            campaigns=campaigns,\n            schedules=schedules,\n            scheduler_reports=scheduler_reports,\n            stability=stability,\n            source_trust_profiles=profiles,\n            source_trust_events=events,\n        )\n\n    async def run_due_and_snapshot(self, limit: int | None = None) -> Dict[str, Any]:\n        run_result = await self.stability_service.run_scheduler_due_with_recovery(limit=limit)\n        snap = self.snapshot()\n        snap["last_operation"] = {"operation": "run_due_with_recovery", "result": run_result}\n        return snap\n\n    async def refresh_campaign_and_snapshot(self, campaign_id: str) -> Dict[str, Any]:\n        refresh_result = await self.stability_service.refresh_campaign_with_recovery(campaign_id)\n        snap = self.snapshot()\n        snap["last_operation"] = {\n            "operation": "refresh_campaign_with_recovery",\n            "campaign_id": campaign_id,\n            "result": refresh_result,\n        }\n        return snap\n\n    def _safe(self, fn, fallback):\n        try:\n            return fn()\n        except Exception:\n            return fallback\n', 'src/claire/internet_operations_dashboard/static_page.py': 'DASHBOARD_HTML = \'<!doctype html>\\n<html>\\n<head>\\n  <meta charset=\\\'utf-8\\\'>\\n  <title>Claire Internet Operations Dashboard</title>\\n  <style>\\n    body { font-family: Arial, sans-serif; margin: 24px; background: #0f172a; color: #e2e8f0; }\\n    h1 { margin-bottom: 4px; }\\n    .muted { color: #94a3b8; }\\n    .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 16px; margin-top: 20px; }\\n    .card { background: #111827; border: 1px solid #334155; border-radius: 12px; padding: 16px; }\\n    .healthy { color: #22c55e; }\\n    .degraded, .warning { color: #f59e0b; }\\n    .error { color: #ef4444; }\\n    button { background: #2563eb; color: white; border: 0; border-radius: 8px; padding: 8px 12px; cursor: pointer; }\\n    input { padding: 8px; border-radius: 8px; border: 1px solid #475569; background: #020617; color: #e2e8f0; }\\n    pre { white-space: pre-wrap; background: #020617; border: 1px solid #334155; border-radius: 8px; padding: 12px; max-height: 420px; overflow: auto; }\\n  </style>\\n</head>\\n<body>\\n  <h1>Claire Internet Operations Dashboard</h1>\\n  <div class=\\\'muted\\\'>Governed internet campaigns, scheduler health, runtime stability, and source trust.</div>\\n  <p>\\n    <button onclick=\\\'loadSnapshot()\\\'>Refresh Dashboard</button>\\n    <button onclick=\\\'runDue()\\\'>Run Due Updates</button>\\n    <input id=\\\'campaignId\\\' placeholder=\\\'campaign_id for manual refresh\\\'>\\n    <button onclick=\\\'refreshCampaign()\\\'>Refresh Campaign</button>\\n  </p>\\n  <div id=\\\'summary\\\' class=\\\'grid\\\'></div>\\n  <h2>Raw Snapshot</h2>\\n  <pre id=\\\'raw\\\'>Loading...</pre>\\n  <script>\\n    async function loadSnapshot() {\\n      const res = await fetch(\\\'/internet/ops/snapshot\\\');\\n      render(await res.json());\\n    }\\n    async function runDue() {\\n      const res = await fetch(\\\'/internet/ops/run-due\\\', { method: \\\'POST\\\' });\\n      render(await res.json());\\n    }\\n    async function refreshCampaign() {\\n      const id = document.getElementById(\\\'campaignId\\\').value.trim();\\n      if (!id) { alert(\\\'Enter campaign_id\\\'); return; }\\n      const res = await fetch(\\\'/internet/ops/campaigns/\\\' + encodeURIComponent(id) + \\\'/refresh\\\', { method: \\\'POST\\\' });\\n      render(await res.json());\\n    }\\n    function render(data) {\\n      document.getElementById(\\\'raw\\\').textContent = JSON.stringify(data, null, 2);\\n      const summary = document.getElementById(\\\'summary\\\');\\n      summary.innerHTML = \\\'\\\';\\n      for (const panel of (data.panels || [])) {\\n        const div = document.createElement(\\\'div\\\');\\n        div.className = \\\'card\\\';\\n        div.innerHTML = \\\'<h3>\\\' + panel.panel + \\\'</h3>\\\' +\\n          \\\'<div>Status: <b class="\\\' + panel.status + \\\'">\\\' + panel.status + \\\'</b></div>\\\' +\\n          \\\'<div>Count: \\\' + panel.count + \\\'</div>\\\';\\n        summary.appendChild(div);\\n      }\\n      const recs = data.recommendations || [];\\n      const rec = document.createElement(\\\'div\\\');\\n      rec.className = \\\'card\\\';\\n      rec.innerHTML = \\\'<h3>Recommendations</h3>\\\' + (recs.length ? \\\'<ul>\\\' + recs.map(r => \\\'<li>\\\' + r + \\\'</li>\\\').join(\\\'\\\') + \\\'</ul>\\\' : \\\'<div>No recommendations.</div>\\\');\\n      summary.appendChild(rec);\\n    }\\n    loadSnapshot();\\n  </script>\\n</body>\\n</html>\\n\'\n', 'src/claire/internet_operations_dashboard/api_routes.py': '\nfrom __future__ import annotations\n\nfrom typing import Optional\n\nfrom fastapi import APIRouter\nfrom fastapi.responses import HTMLResponse\n\nfrom .service import InternetOperationsDashboardService\nfrom .static_page import DASHBOARD_HTML\n\n\nrouter = APIRouter(prefix="/internet/ops", tags=["Internet Operations Dashboard"])\n\n\n@router.get("/snapshot")\ndef snapshot():\n    service = InternetOperationsDashboardService()\n    return service.snapshot()\n\n\n@router.post("/run-due")\nasync def run_due(limit: Optional[int] = None):\n    service = InternetOperationsDashboardService()\n    return await service.run_due_and_snapshot(limit=limit)\n\n\n@router.post("/campaigns/{campaign_id}/refresh")\nasync def refresh_campaign(campaign_id: str):\n    service = InternetOperationsDashboardService()\n    return await service.refresh_campaign_and_snapshot(campaign_id)\n\n\n@router.get("/dashboard", response_class=HTMLResponse)\ndef dashboard_page():\n    return DASHBOARD_HTML\n', 'tests/internet_operations_dashboard/test_internet_operations_dashboard.py': '\nfrom claire.internet_operations_dashboard.payloads import DashboardPayloadBuilder\nfrom claire.internet_operations_dashboard.service import InternetOperationsDashboardService\n\n\nclass FakeCampaigns:\n    def list_campaigns(self):\n        return [{"campaign_id": "c1", "name": "Campaign"}]\n\n\nclass FakeScheduler:\n    def list_schedules(self):\n        return [{"campaign_id": "c1", "cadence_minutes": 1440}]\n\n    def list_reports(self):\n        return [{"scheduler_run_id": "r1", "status": "completed"}]\n\n\nclass FakeStability:\n    def health(self):\n        return {"status": "healthy"}\n\n    async def run_scheduler_due_with_recovery(self, limit=None):\n        return {"status": "completed"}\n\n\nclass FakeTrust:\n    def list_profiles(self):\n        return [{"domain": "sec.gov", "status": "active"}]\n\n    def list_events(self, domain=None, limit=25):\n        return [{"domain": "sec.gov", "event_type": "confirmed"}]\n\n\ndef test_payload_builder_snapshot():\n    builder = DashboardPayloadBuilder()\n    snap = builder.build(\n        campaigns=[{"campaign_id": "c1"}],\n        schedules=[{"campaign_id": "c1"}],\n        scheduler_reports=[],\n        stability={"status": "healthy"},\n        source_trust_profiles=[],\n        source_trust_events=[],\n    )\n    assert snap["status"] == "healthy"\n    assert len(snap["panels"]) == 6\n\n\ndef test_dashboard_service_snapshot():\n    service = InternetOperationsDashboardService(\n        campaign_service=FakeCampaigns(),\n        scheduler_service=FakeScheduler(),\n        stability_service=FakeStability(),\n        source_trust_service=FakeTrust(),\n    )\n    snap = service.snapshot()\n    assert snap["campaigns"][0]["campaign_id"] == "c1"\n    assert snap["stability"]["status"] == "healthy"\n    assert snap["source_trust_profiles"][0]["domain"] == "sec.gov"\n', 'tests/internet_operations_dashboard/test_internet_operations_dashboard_api.py': '\nfrom fastapi import FastAPI\nfrom fastapi.testclient import TestClient\n\nfrom claire.internet_operations_dashboard import api_routes\nfrom claire.internet_operations_dashboard.service import InternetOperationsDashboardService\n\n\ndef test_snapshot_route(monkeypatch):\n    app = FastAPI()\n    app.include_router(api_routes.router)\n\n    def fake_snapshot(self):\n        return {"status": "healthy", "panels": []}\n\n    monkeypatch.setattr(InternetOperationsDashboardService, "snapshot", fake_snapshot)\n\n    client = TestClient(app)\n    response = client.get("/internet/ops/snapshot")\n    assert response.status_code == 200\n    assert response.json()["status"] == "healthy"\n\n\ndef test_dashboard_page_route():\n    app = FastAPI()\n    app.include_router(api_routes.router)\n\n    client = TestClient(app)\n    response = client.get("/internet/ops/dashboard")\n    assert response.status_code == 200\n    assert "Claire Internet Operations Dashboard" in response.text\n', 'docs/internet_operations_dashboard/v17_47_internet_operations_dashboard.md': "\n# Claire v17.47 — Internet Operations Dashboard Layer\n\nThis package adds an operational dashboard API and standalone local HTML dashboard for Claire's governed internet runtime.\n\n## FastAPI Wiring\n\n```python\nfrom claire.internet_operations_dashboard.api_routes import router as internet_ops_dashboard_router\napp.include_router(internet_ops_dashboard_router)\n```\n\n## Routes\n\n- `GET /internet/ops/snapshot`\n- `POST /internet/ops/run-due`\n- `POST /internet/ops/campaigns/{campaign_id}/refresh`\n- `GET /internet/ops/dashboard`\n", 'src/frontend/internet_operations_dashboard/internet_operations_dashboard.html': '\n<!doctype html>\n<html><head><meta charset="utf-8"><title>Claire Internet Operations Dashboard</title></head>\n<body><h1>Claire Internet Operations Dashboard</h1><p>Use FastAPI route <code>/internet/ops/dashboard</code>.</p></body></html>\n', 'data/internet_operations_dashboard/internet_operations_dashboard_manifest.json': '{\n  "layer": "internet_operations_dashboard",\n  "version": "v17.47",\n  "status": "installed",\n  "requires": [\n    "claire.persistent_internet_campaigns",\n    "claire.governed_campaign_scheduler",\n    "claire.internet_runtime_stability",\n    "claire.dynamic_source_trust"\n  ],\n  "capabilities": [\n    "dashboard_snapshot",\n    "campaign_panel_payload",\n    "scheduler_panel_payload",\n    "stability_panel_payload",\n    "source_trust_panel_payload",\n    "run_due_control_endpoint",\n    "manual_campaign_refresh_endpoint",\n    "standalone_html_dashboard",\n    "tests"\n  ],\n  "governance_boundary": "dashboard_controls_call_existing_governed_services_only"\n}'}

def main() -> None:
    print("Installing Claire v17.47 Internet Operations Dashboard Layer...")
    for rel_path, content in FILES.items():
        path = ROOT / rel_path
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content.strip() + "\n", encoding="utf-8")
        print(f"WROTE {rel_path}")
    print("")
    print("INSTALL COMPLETE: Claire v17.47 Internet Operations Dashboard Layer")
    print("")
    print("Run tests with:")
    print("    python -m pytest tests/internet_operations_dashboard -q")
    print("")
    print("Optional route wiring:")
    print("    from claire.internet_operations_dashboard.api_routes import router as internet_ops_dashboard_router")
    print("    app.include_router(internet_ops_dashboard_router)")

if __name__ == "__main__":
    main()
